{
  "activities": [
    {
      "type": "activity",
      "title": "Portfolio Write-up on Periodic Classification of Elements",
      "unit_name": "Unit 1",
      "chapter_name": "Chemical Substances - Nature and Behaviour",
      "details": "Learners read about Döbereiner's Triads, Newlands' Law of Octaves, Mendeléev's Periodic Table, and the Modern Periodic Table. They prepare a brief write-up for their portfolio to reinforce understanding without summative assessment stress."
    },
    {
      "type": "activity",
      "title": "Portfolio Write-up on Heredity and Evolution",
      "unit_name": "Unit 2",
      "chapter_name": "World of Living",
      "details": "Learners read about Acquired and Inherited Traits, Speciation, Evolution and Classification, Tracing Evolutionary Relationships, Fossils, and Human Evolution. They prepare a brief write-up for their portfolio."
    },
    {
      "type": "activity",
      "title": "Portfolio Write-up on Electric Effects of Current",
      "unit_name": "Unit 4",
      "chapter_name": "Effects of Current",
      "details": "Learners read about Motors, Electromagnetic Induction, and Electric Generators. They prepare a brief write-up for their portfolio to gain conceptual clarity."
    },
    {
      "type": "activity",
      "title": "Case Study on Science in Human Life",
      "unit_name": "Unit 5",
      "chapter_name": "Natural Resources",
      "details": "Examine a case study related to the use of Science in human life from the perspective of Social Sciences and Ethics (e.g., Marie Curie, Jenner, treatment of patients with mental illnesses, the story of the atomic bomb, green revolution and GMOs, conservation of biodiversity)."
    },
    {
      "type": "activity",
      "title": "Science in Arts and Literature Exploration",
      "unit_name": "Unit 5",
      "chapter_name": "Natural Resources",
      "details": "Explore how literature and arts have influenced Science."
    }
  ],
  "projects": [
    {
      "title": "Construct Simple Machines",
      "unit_name": "Unit 3",
      "chapter_name": "Natural Phenomena",
      "details": "Demonstrate the principle of mechanical advantage by constructing simple machines, specifically a system of levers and pulleys."
    },
    {
      "title": "Environmental Problem Solutions Project",
      "unit_name": "Unit 5",
      "chapter_name": "Natural Resources",
      "details": "Investigate environmental problems such as ozone depletion and waste production, and propose solutions for biodegradable and non-biodegradable substances."
    }
  ],
  "practicals": [
    {
      "title": "Finding pH of Various Samples",
      "unit_name": "Unit 1",
      "chapter_name": "Chemical Substances - Nature and Behaviour",
      "details": "Find the pH of dilute Hydrochloric Acid, Dilute NaOH solution, Dilute Ethanoic Acid solution, Lemon juice, Water, and Dilute Hydrogen Carbonate solution using pH paper/universal indicator."
    },
    {
      "title": "Properties of Acids and Bases",
      "unit_name": "Unit 1",
      "chapter_name": "Chemical Substances - Nature and Behaviour",
      "details": "Study the properties of acids (HCl) and bases (NaOH) based on their reaction with Litmus solution, Zinc metal, and Solid sodium carbonate."
    },
    {
      "title": "Classification of Chemical Reactions",
      "unit_name": "Unit 1",
      "chapter_name": "Chemical Substances - Nature and Behaviour",
      "details": "Perform and observe reactions including action of water on quicklime, action of heat on ferrous sulphate crystals, iron nails in copper sulphate solution, and reaction between sodium sulphate and barium chloride solutions. Classify them as combination, decomposition, displacement, or double displacement."
    },
    {
      "title": "Reactivity Series of Metals",
      "unit_name": "Unit 1",
      "chapter_name": "Chemical Substances - Nature and Behaviour",
      "details": "Observe the action of Zn, Fe, Cu, and Al metals on salt solutions (ZnSO4, FeSO4, CuSO4, Al2(SO4)3). Arrange the metals in decreasing order of reactivity based on results."
    },
    {
      "title": "Ohm's Law Verification",
      "unit_name": "Unit 4",
      "chapter_name": "Effects of Current",
      "details": "Study the dependence of potential difference (V) across a resistor on the current (I) passing through it, determine its resistance, and plot a graph between V and I."
    },
    {
      "title": "Equivalent Resistance Calculation",
      "unit_name": "Unit 4",
      "chapter_name": "Effects of Current",
      "details": "Determine the equivalent resistance of two resistors when connected in series and parallel."
    },
    {
      "title": "Stomata Observation",
      "unit_name": "Unit 2",
      "chapter_name": "World of Living",
      "details": "Prepare a temporary mount of a leaf peel to show stomata."
    },
    {
      "title": "Respiration and CO2 Release",
      "unit_name": "Unit 2",
      "chapter_name": "World of Living",
      "details": "Experimentally show that carbon dioxide is given out during respiration."
    },
    {
      "title": "Properties of Acetic Acid",
      "unit_name": "Unit 1",
      "chapter_name": "Chemical Substances - Nature and Behaviour",
      "details": "Study the properties of acetic acid (ethanoic acid) including odour, solubility in water, effect on litmus, and reaction with Sodium Hydrogen Carbonate."
    },
    {
      "title": "Soap Cleaning Capacity Test",
      "unit_name": "Unit 1",
      "chapter_name": "Chemical Substances - Nature and Behaviour",
      "details": "Study the comparative cleaning capacity of a sample of soap in soft and hard water."
    },
    {
      "title": "Focal Length Determination",
      "unit_name": "Unit 3",
      "chapter_name": "Natural Phenomena",
      "details": "Determine the focal length of a concave mirror and a convex lens by obtaining the image of a distant object."
    },
    {
      "title": "Refraction through Glass Slab",
      "unit_name": "Unit 3",
      "chapter_name": "Natural Phenomena",
      "details": "Trace the path of a ray of light passing through a rectangular glass slab for different angles of incidence. Measure the angle of incidence, angle of refraction, and angle of emergence."
    },
    {
      "title": "Binary Fission and Budding Study",
      "unit_name": "Unit 2",
      "chapter_name": "World of Living",
      "details": "Study binary fission in Amoeba and budding in yeast and Hydra with the help of prepared slides."
    },
    {
      "title": "Light Refraction through Prism",
      "unit_name": "Unit 3",
      "chapter_name": "Natural Phenomena",
      "details": "Trace the path of the rays of light through a glass prism."
    },
    {
      "title": "Embryo Identification",
      "unit_name": "Unit 2",
      "chapter_name": "World of Living",
      "details": "Identify the different parts of an embryo of a dicot seed (pea, gram, or red kidney bean)."
    }
  ]
}
